import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const POLY = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  // Step 1: Single broad discovery call to avoid same-endpoint parallel spray
  const discovery = await callMcpSkill({
    toolId: POLY,
    toolName: "search_markets",
    args: { query: "boots on the ground Iran ground invasion US troops allied forces military strike war", status: "live", limit: 50 }
  });

  const candidates = Array.isArray(discovery?.results) ? discovery.results : [];

  if (candidates.length === 0) {
    return {
      summary: { totalMarketsFound: 0, directGroundWarMarkets: 0, broaderIranMilitaryMarkets: 0 },
      directGroundWarMarkets: [],
      broaderIranMilitaryMarkets: [],
      riskOffFramework: { coreInsight: "No live Iran military markets found on Polymarket.", howToThinkAboutIt: [], hedgingImplications: [] },
      fetchedAt: new Date().toISOString()
    };
  }

  // Step 2: Deterministic semantic targeting — rank into two legs
  const directLeg = pickTopSemanticCandidates({
    target: "US or allied boots on the ground in Iran — ground invasion, ground troops, military occupation",
    candidates,
    requiredTerms: ["boots", "ground", "invasion", "troops", "iran"],
    avoidTerms: ["airstrike", "strike only", "bombing", "cyber", "sanctions", "negotiate", "diplomatic", "nuclear deal"],
    limit: 10
  });

